DROP TABLE IF EXISTS `club_gallery`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `club_gallery` (
  `galleryID` int NOT NULL AUTO_INCREMENT,
  `clubID` int NOT NULL,
  `imageUrl` varchar(500) NOT NULL,
  `caption` varchar(200) DEFAULT NULL,
  `uploadedAt` datetime DEFAULT CURRENT_TIMESTAMP,
  `featured` tinyint(1) DEFAULT '0',
  `featuredClubPage` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`galleryID`),
  KEY `clubID` (`clubID`),
  CONSTRAINT `club_gallery_ibfk_1` FOREIGN KEY (`clubID`) REFERENCES `clubs` (`clubID`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=549 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
