INSERT INTO `events` VALUES (1,1,'SPLASH & SPILL','?? Make a splash at “Splash & Spill”!\nCool mocktails, hot beats & poolside vibes — don’t miss out! ???\n? 24th Sept | 5 PM onwards\n? Piazza & Pool | RM10 Vision / RM15 Non-Vision\nDress code: Swimsuits, summer fits, or casual cool ?\n?️ Scan the QR to get your tickets now!\n#vision #fun #pool #poolparty #visionpresents','2025-09-24 09:00:00','Piazza & Pool',1,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1781977281/r1tisf8i7tcb2rf95irk.jpg'),(2,6,'YOUTH TALKS','Join us for the second session of Youth Talks, featuring the Faculty of Information Technology!\n\nHear from Dr. Nurbaini Zainuddin and our outstanding student Suhayma Junaid as they share valuable insights, experiences, and perspectives on navigating the digital world and building a future in technology.\n\n✨ Real Stories. Real Impact.\n✨ Learn from industry and academic experiences.\n✨ Ask questions, gain insights, and get inspired.\n\n? 16 June 2026\n? Auditorium A, SEGi University\n⏰ 2:00 PM – 3:00 PM\n\n? Refreshments included!\n\nRegister now and secure your seat. ?\n\n#YouthTalksSEGi #YouthOfHope #FacultyOfIT #ThinkSecureLeadDigital #SEGiUniversity InspireLearnLead','2026-06-15 14:00:00',' Auditorium A, SEGi University',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782622300/ktwnxqh25euwlzpxcnun.png'),(3,6,'VOLLEYBALL SESSION','Join us this Friday for an exciting Volleyball Gathering! A great chance to stay active, meet new friends, and enjoy some friendly competition. ??\n\n? Friday, 12 June 2026\n⏰ 6:00 PM – 8:00 PM\n? SEGi University Volleyball Court\n\n⚠️ Limited slots available — register now!','2026-06-12 18:00:00','SEGi University Volleyball Court',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782622477/ss5uxmqasz58kntac0nl.png'),(4,6,'GIRL\'S BADMINTON','? Girls’ Badminton Evening ?\n\nAn hour of fun, fitness, and sisterhood awaits! ?✨\n\n? Sri KDU\n? 14 June 2026\n? 6:00 PM – 7:00 PM\n? RM6\n\n⚠️ Limited slots available — register now','2026-06-14 02:00:00','Sri KDU',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782622940/h3s5ftx2wvlmxhqttq5l.png'),(5,6,'GRILL & CHILL','Ready to grill, chill & make unforgettable Eid memories? ??✨\n\nJoin us for a fun-filled beach BBQ day with games, good vibes, photo sessions, and meaningful moments together ?\n\n? Port Dickson\n? 30/5/2026\n? RM45 per person\n\nSpots are limited, so don’t wait too long ?\nScan the QR code to register now! ??','2026-05-30 08:00:00','Port Dickson',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782622750/cfidbuwvqpzircj7fqoh.png'),(6,6,'RAMADAN IFTAR','Gathering hearts, sharing blessings. Ramadan Iftar ??\n','2026-03-08 19:00:00','MPH',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782623023/sjhdc39fxxfacmjqkskv.png'),(7,6,'GIRL\'S BADMINTON SESSION','? Youth of Hope – Girls’ Badminton Session ?\n\nAssalamu’alaikum sisters ?\nWe’re excited to announce that our Girls’ Badminton Session will be happening every Friday, InshaAllah ?✨\n\n? Time: 6:00 pm – 8:30 pm\n? Break: 7:20 pm (Maghrib prayer)\n? Venue: MPH\n\n✅ Free entrance\n✅ Please bring your own racket and shuttle if you have\n✅ All girls are most welcome to join! ?\n\nWe’re also planning more sports sessions soon, InshaAllah ?\n\nCome join us, make new friends, and have fun together! Hope to see you all there ?✨','2025-09-26 18:00:00','MPH',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782623221/kmcijrn93lp8em8zy8dr.png'),(8,6,'EID TRIP','?YOUTH OF HOPE CLUB ANNOUNCEMENT?\n\nEid Al-Adha Prayer Trip 2025 — Register Now!\nPutrajaya Mosque | RM 20 Only | Limited Seats!\n\nAssalamu Alaikum everyone!\nJoin us this Eid for a beautiful spiritual morning at Putrajaya Mosque with the Youth of Hope Club!\n\nDetails:\n? Location: Putrajaya Mosque\n? Meeting Point: University Campus\n? Date: June 6th or 7th(to be confirmed)\n? Transport: Provided\n? Fee: RM 20 (includes transport & light refreshments)\n\nNO cancellations after June 2nd.\nCancellation = Still pay RM 20.\n\nRegister here:\nhttps://forms.gle/s5MhuGDpdnqVrFnz7\n\nLet’s make this Eid memorable together!\nFirst come, first served. Club members get priority.\n\n– Youth of Hope Team','2025-06-02 06:15:00','Putrajaya Mosque',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782623544/wd9s8ei92wtjkwufzvor.png'),(9,10,'TALENT SHOW','TALENT. ENERGY. ENTERTAINMENT.??\n\nThe stage is set for one of the most exciting nights at SEGi University\nFrom singing and dancing to magic and creative performances, the SEGi Talent Show is where students come together to showcase their talent and light up the stage ??\n\n? July 10\n⏰ 6PM – 9PM\n? Auditorium A\n? RM15 Entry Fee\nREGISTER NOW\n\nSEGi Students Only.\nBring your friends and don’t miss the show ?\n#segi #siss #talenshow\n\nSHOW US YOUR TALENT ?✨\nThis is your chance to perform on stage and shine in front of everyone.\nSing, dance, or perform anything creative we want\nYOU on stage ?\n\n⚠️ Limited performance slots available\nRegister now and secure your spot','2026-07-10 18:00:00','Auditorium A',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782623718/jboclf3gyvfuntzklces.png'),(10,10,'FUTSAL TOURNAMENT','Who’s ready to dominate the court at SEGi? Joining the upcoming Futsal Tournament this May. Scan the QR code in the pic to register your squad or DM me if you want to ask further! ??\n#siss2526 #fy #siss #futsal #sport','2026-05-22 18:00:00','Multi-purpose Court',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782623874/k0m4yiwoidaamhpatc1u.png'),(11,10,'PASSPORT TO THE CULTURAL WORLD','Ready for a trip around the world without the jet lag? ✈️?\n\nSEGi University presents Passport to the Cultural World ?✨An evening of culture and performances, all in one vibrant experience. Open to everyone.\n\n?️ From RM10\n?️ 12 June 2026 | 7.00 PM\n? MPH, SEGi University\n\n#SEGiUniversity #CulturalNight #GlobalExperience #FoodAndCulture #StudentLife #SEGiEvents #CampusLife #ExperienceTheWorld','2026-06-12 19:00:00','MPH ',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782624127/uy7inirx0tfv3afymdjx.png'),(12,10,'Ramadhan Bazaar & Iftar Gathering','? Ramadhan Bazaar & Iftar Gathering ?\n\n? Thursday, 5th March\n⏰ 10:00 AM – 9:00 PM\n? SEGi University Campus\n\nJoin us for delicious food, drinks, and a warm Ramadhan vibe with your friends and family!\n✨ Open to outsiders – invite everyone!\n\n? Tarawih prayer will be held at MPH.\nFrom 8:30 PM onwards, gathering will continue at:\n? Piazza (Outdoor) or\n? SCCL1 (Indoor)\n\nLet’s celebrate this blessed month together ??\n#segi #siss #ramadan #i̇ftar #bazaar','2026-03-05 10:00:00','Piazza',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782624407/srvrflmpdszargr9rpmo.png'),(13,10,'INTERNATIONAL FOOD BAZAAR','? International Food Bazaar ?\n\nJoin us every Tuesday, Wednesday & Thursday for a variety of delicious international iftar selections!\n?️ Different countries, diverse flavors, meaningful moments, and shared blessings.\n\n? Cafeteria, SEGi University\n⏰ 3:00 PM – 7:00 PM\n\nNot sure what to eat for iftar? We’ve got you covered ?\n','2026-02-13 15:00:00','Cafeteria, SEGi University ',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782624565/hutv2fq7rif34a2rcx12.png'),(14,10,'ICN25 – International Cultural Night','✨ ICN25 – International Cultural Night is here! ✨?\nAcross cultures, toward unity ?\n\n? Food Fair: 29 Oct 2025 @ Piazza, SEGi University\n? Main Event: 30 Oct 2025 @ Multipurpose Hall\n?️ Tickets only RM20 – Scan the QR code to book yours now!\n\nDon’t miss out on a night of culture, food & celebration ??\n#ICN25 #InternationalCulturalNight #AcrossCulturesTowardUnity','2025-10-30 18:00:00','MPH',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782624811/glzeinzec4z35y3ugrav.png'),(15,7,'RAMADAN OFFERING','? Ramadhan Offerings ?\nCelebrate the blessings of Ramadhan with SUVC?\n\nJoin us on March 13th for a campus wide Ramadhan celebration with free meals for all✨\n\nLet’s share the blessings together?','2025-03-13 17:00:00','Dictator Stage',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782625146/mgjryutgtgaziqnxx3yp.png'),(16,7,'HOUSE OF HORRORS','The town whispers about a house that never lets go. Shadows remember names. Footsteps echo where no one should tread.\nThis November, House of Horrors invites the brave to NO WAY OUT.\n\nWander blood-stained hallways, follow the lullaby of something hungry, and learn why the moon won’t look you in the eye. Those who enter may find their screams answered… and their names scratched into the walls.\n\n5th November 2025 • ⏰ 6PM–10PM • ? MPH, SEGi University\n\nTickets move fast. If you value your pulse, bring a friend. If you don’t… come alone.\n\nIn collaboration with: @segivmac','2025-11-05 18:00:00','MPH',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782625273/jesrktl8l0vjmx3halnq.png'),(17,7,'PICNIC WITH SUVC','Good people. Green views. Great vibes. ??\nPicnic with SUVC ✨','2025-01-24 11:00:00',NULL,2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782625471/gytteciqzkoyjmjfojts.png'),(18,7,'PAWSITIVE VOLUTEERS','They can’t ask for help.\nBut they know when it arrives.\n\nTo every volunteer who gives their time, patience, and love this is what kindness looks like.\n\n#PawsitiveVolunteers #VolunteerWithPurpose\n#AnimalWelfareMY #GaleriAnimalMalaysia\n#UniversityVolunteers BeTheirVoice ?','2026-03-14 10:00:00','Galeri Animal Malaysia',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782625675/ongpwa9obczcpdbkpo1j.png'),(19,9,'VOLLEYBALL TOURNAMENT','Collab alert ??\nWe’re excited to partner with @segivmac for a fun volleyball event!\nNo pressure, just good energy, teamwork, and great games ?\n\nget ready\nA Volleyball tournament is coming your way!\nGrab your friends, build your dream team, and bring the energy to the court.\nSave the date, scan the QR to register, and send your proof to our DM.\nLet\'s make this one unforgettable. New year new energy.\nSee you soon!!\n\n? MCP\n? 23,24 January\n⏰ 7pm-11pm\n\nEveryone’s welcome ?','2026-01-23 19:00:00','MCP',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782628729/fq0cqkmi2eckc87lfr2q.png'),(20,1,'SHOOT & VIBE','Shoot your shot ?✨\nPhotographers, models, and creatives come link up, vibe, and create something real.\n\n? SEGi Garden & Fountain Area, Kota Damansara\n? 20 May 2026 | ⏰ 4–6PM\n\nPull up with your vision or just come catch the vibe.','2026-05-20 08:00:00','SEGi Garden & Fountain Area, Kota Damansara',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782628864/rgrryxsfx7ubcwsgwq5k.png'),(21,1,'ROYAL STARLIGHT - PROM NIGHT 2026','The secret is officially out! ?✨ Mark your calendars for an evening where the stars align. You won’t want to miss the most magical night of the year.\n\n? Date: 3rd July 2026\n? Venue: SEGi College Subang Jaya\n? Ticket Price: RM80 (Includes Dinner & Entertainment)\n\nGet ready to shine at Royal Starlight Prom Night! Scan the QR or DM us to secure your spot now! ??','2026-07-03 17:30:00','Segi College, Subang Jaya',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782629091/haovt8oj9v5j46c9qk0n.png'),(22,1,'ACTING WORKSHOP','? ACTING WORKSHOP ?\n\nLights, camera… YOU?! ?\n\nStep into the spotlight with our Stage & Screen Acting Basics Workshop hosted by the amazing Dinara Elia ??\n\n? 23rd July 2025\n? 3:00PM – 6:00PM\n? Auditorium B, SEGi University (Left Wing, Level 2)\n\n? Open to Vision members with little to NO experience — just bring your curiosity and love for performing!\nGet ready to express, emote, and connect with your inner performer! ?✨','2025-07-23 15:00:00',' Auditorium B, SEGi University (Left Wing, Level 2)',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782629297/bt8cvgraiykwyzlfr1qr.png'),(23,1,'BUILD YOUR SOUND','? BUILD YOUR SOUND ?\n\nEver wanted to record your own music? Or just understand how a home studio works? ??️\n\nJoin us for an Introduction to Home Recording & Music Production ?️ with Nicholas & Max, industry experts in sound and music!\n\n? 16th July 2025\n? 2:00PM\n? Sony Radio Studio, SEGi Tower (Level 13)\n\n? Learn studio essentials, production basics, and how to bring your sound to life — even if you’re a total beginner.\n\n✨ Don’t miss your chance to start building YOUR sound.','2025-07-16 17:00:00','Sony Radio Studio, SEGi Tower (Level 13)',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782629634/nwxivzwbop7fgcsrkyep.png'),(24,1,'FASHION PHOTOSHOOT','Hey everyone! We’re excited to invite you to a Fashion Photoshoot Workshop hosted by Vision Multimedia Club?✨\n\n?️ Date: 9th July 2025\n? Time: 3:00PM – 6:00PM\n? Venue: Sony Radio Studio, SEGi Tower (Level 13)\n\nThis is a perfect opportunity to:\n? Enhance your fashion photoshoot skills\n? Learn as a model\n? Improve your portfolio\n\nWhether you’re a beginner or looking to refine your skills, this hands-on workshop is for YOU! Don’t miss out! ?','2025-07-09 15:00:00','Sony Radio Studio, SEGi Tower (Level 13)',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782629739/zmcatvuybvvldgbsiwrf.png'),(25,9,'SMASH & SPIKE','We’re excited to invite you to join our upcoming Volleyball Tournament!\n- Each team can register up to 9 players, with a minimum of 6 players required to start a match and\n- ⁠Must have at least 1 female player on court at all times.\n- ⁠All matches will follow the standard rules set FIVB.\n\nhttps://docs.google.com/forms/d/e/1FAIpQLSeBCvlAs8Q3gshtSySSCc_6LH-b85_7BTWMjbueRdiB_Mx5Tg/viewform?usp=dialog\n','2026-05-19 19:00:00','MPH & MPC',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782629985/jphbawiodzzptikfuw0g.png'),(26,11,'AQUATIC PARTY','?You’re Invited! Win the game and claim the goody bag filled with treats and surprises! Are you ready to play?\n\nAquatic Party ??\n?️18th April 2024\n⏰6PM - 8PM\n?Piazza, SEGi University\n?️RM25 / person\n?Follow @segitaekwondo on Instagram for a RM5 discount\n\n?Registration Link in Bio\n\nFor More Information:\n016-713 8622 (Coco)\n011-1140 2128 (Gabrielle)','2024-04-18 18:00:00','Piazza, SEGi University',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782630231/ygxrnzc4h77vxuhuedps.png'),(27,8,'2025 SEGI 3X3','Welcome to register it?','2025-03-25 18:30:00','MPC',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782630417/wcsryqi1oana6rlxsztl.png'),(28,8,'2026 SEGI 3X3 ','Welcome to register','2026-07-02 11:30:00','MPC',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782630603/mhs78hmv6zskhx8i7ux5.png'),(29,36,'流光岛 ECHOES OF LIGHT','?️ 流光岛 · Echoes of Light\n一座不在地图上的岛，正在等你靠岸 ?\n\n在这里，光会说话，回忆会发光 ✨\n一起走进童年的世界，把遗失的快乐找回来\n\n? 6.6，我们在流光岛见 ?\n\n?️ 活动详情\n? 日期｜6.6.2026（星期六）\n⏰ 时间｜9:00am – 7:00pm\n? 地点｜哥打白沙罗世纪大学 MPH\n（SEGi University Kota Damansara）\n\n✨ 登岛时间已提前开放\n让你能在流光岛停留更久\n体验更多童年的快乐 ?️?\n\n?️ 票价\nRM38｜单人票（SEGi学生）\nRM40｜单人票（非SEGi学生）\nRM190｜5人团购\n\n? 报名方式\n扫码成为岛民吧 ?️?\nhttps://forms.gle/Zor6tiJVVk8D7x3X6\n\n? 联系我们\n? 龙静琳｜018-9104039\n? 吕珍妮｜011-13260127\n? 洪依宁｜016-7202800\n\n✨ 包含营服与午餐（T-shirt & Lunch Provided）\n\n?️ Echoes of Light · Flowing Island\nAn island that doesn’t exist on any map, waiting for you to arrive ?\n\nHere, light speaks and memories shine ✨\nStep into the world of your childhood and rediscover lost joys.\n\n? See you on the island on 6.6! ?\n\n?️ Event Details\n? Date: 6 June 2026 (Saturday)\n⏰ Time: 9:00 AM – 7:00 PM\n? Venue: SEGi University Kota Damansara, MPH\n\n✨ Boarding time is now open earlier\nStay longer on the island and relive more childhood joy ?️✨\n\n?️ Tickets\nRM38 | Individual (SEGi students)\nRM40 | Individual (Non-SEGi students)\nRM190 | Group of 5\n\n? Sign Up\nBecome an islander now ?️?\nhttps://forms.gle/Zor6tiJVVk8D7x3X6\n\n? Contact Us\n? Long Chin Ling ｜ 018-9104039\n? Loo Zhen Nee ｜ 011-13260127\n? Ang Eileen ｜ 016-7202800\n\n✨ Includes camp uniform & lunch (T-shirt & Lunch Provided)\n\n#流光岛\n#echoesoflight\n#岛上集合\n#你的童年我的童年好像不一样\n#segikdccs','2026-06-06 09:00:00','SEGi University Kota Damansara, MPH',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782631069/p0bbckj0nxs1bf6vgqof.png'),(30,36,'GALA NIGHT (REUNION REVERIE)','?? 重磅阵容公开 · Yiha 团队空降！ ??\n\n这个新春夜晚，《缘 · 聚》的舞台全面升级 ⚡️\n\n? Yiha 团队 重磅到场\nMaqlai、Ashley、Belle、Suzanne、Sam、Edmund\n\n强节奏 · 强舞台 · 强互动\n六人同台，气氛自然拉满 ?\n音乐一响，节奏一到，\n现场不只是观看，\n而是全场一起参与的狂欢 ??\n\n想和朋友一起嗨？\n想感受真正的现场气氛？\n这个夜晚，Yiha 团队陪你把新春过到最尽兴 ?✨\n\n? 28 / 2 / 2026（星期六）\n⏰ 7:00 PM – 10:00 PM\n? MPH SEGi University Kota Damansara\n\n? 报名方式：\n有兴趣的同学请扫描二维码填写报名表单\nhttps://forms.gle/YekWgbHz2Puf1QpA6\n\n⚠️ 位子有限，气氛无限\n? 约好人，直接来《缘 · 聚》！\n———\n\n?? Full Line-up Revealed · Yiha Team Is Here! ??\n\nThis festive night, Reunion Reverie turns up the energy ⚡️\n\n? Yiha Team on stage\nMaqlai · Ashley · Belle · Suzanne · Sam · Edmund\n\nStrong beats · Strong stage · Strong interaction\nSix performers on one stage,\nbringing instant live energy ?\nWhen the music hits and the rhythm drops,\nit’s no longer just a show —\nit’s a celebration everyone joins ??\n\nLooking for a high-energy CNY night?\nBring your friends and be part of it ?✨\n\n? 28 February 2026 (Saturday)\n⏰ 7:00 PM – 10:00 PM\n? MPH SEGi University Kota Damansara\n\n? Registration\nInterested students may scan the QR code to fill in the registration form:\nhttps://forms.gle/YekWgbHz2Puf1QpA6\n\n⚠️ Limited seats, unlimited vibes','2026-02-28 11:00:00','MPH SEGi University',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782631141/pxwwljfyzopki3ubxzon.png'),(31,36,'GALA NIGHT (CRIMSON DESTINY)','们将在下个星期开始售票咯！\n\n《月落三生》活动详情如下：\n日期：18.10.2025\n时间：7pm – 10pm\n地点：MPH SEGi University Kota Damansara\n早鸟票价：RM20/位\n优惠期限：1.7.2025 至 21.7.2025\n\n如有疑问，请联络：\n颜芷熒：016-2811023\n龙静琳：018-9104039\n邬沛瑜：014-3236855\n\n关注我们IG / YouthsOS / 官方群 获取最新消息！\n\n?Early Bird Poster?\n? Woohoo! Our early bird poster is here! Everyone, are you ready? Ticket sales will officially start next week!\n\nHere’s the event info for <Crimson Destiny>:\nDate: 18.10.2025\nTime: 7pm – 10pm\nVenue: MPH SEGi University Kota Damansara\nEarly Bird Price: RM20/pax\nPromotion Period: 1.7.2025 – 21.7.2025\n\nIf you have any questions, please contact：\nZoel Gan Z-Ann：016-2811023\nLong Chin Ling：018-9104039\nPhebe Octovia Voo：014-3236855\n\nFollow us on IG / YouthsOS / Official group for updates!\n\nRegistration Link :\nhttps://app.youths.asia/event/t5zpQSAwLO4LRiEZ2jyQ\n\n#月落三生1018\n#三线牵月\n#月圆三誓\n#crimsondestiny\n#segikdccs','2025-10-18 19:00:00','MPH Segi University',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782631482/uycyrtk2bqjgdr7khcv5.png'),(32,28,'TEKKEN 8 TOURNAMENT','TEKKEN 8 TOURNAMENT ?\n? SEGi University, L1.4 Esport Lab\n? Thursday, March 5th\n⏰ 10:00 AM – 3:00 PM\n\n? Step into the arena and prove your dominance! The ultimate Tekken 8 showdown is happening at SEGi University — are you ready to claim the crown?\n\n? Tournament Details:\n? Entry Fee: RM10 per player\n? 1v1 Competitive Format\n⚡ Bring your best combos, mind games & reactions\n\n? Prize Pool:\n? Champion – RM150 + Certificate of Achievement\n? Second Place – RM70 + Certificate of Achievement\n? Third Place – RM40 + Certificate of Achievement\n\n? Register now:\nhttps://docs.google.com/forms/d/e/1FAIpQLScCyNF2ngfMGEH5neNRJi7_jePzAnAP5KNu7iXguP5WFJwCxA/viewform?usp=dialog\n\n? For further information:\nAmmar – 011-1143 7172\n\n? Whether you’re a seasoned fighter or a rising contender, this is your moment to dominate the arena #gvsmediasquad #tekken8 #combats #esports #Gamers Vault','2026-03-05 10:00:00','SEGi University, L1.4 Esport Lab',2,'https://res.cloudinary.com/dhzxwmkfk/image/upload/v1782631690/sazdicppl8jpz7zxulrf.png'),(33,28,'MOBILE LEGENDS TOURNAMENT','? Segi Gamers, Assemble! ?\nGet ready for the ultimate 5v5 showdown – Gamers Vault x BEPR proudly presents the Mobile Legends: Bang Bang Tournament 2025, hosted at SEGi University! ?✨\n\nWhether you’re a strategic mastermind or a fearless fighter, this is your moment to shine. Rally your squad and battle your way to victory with epic prizes up for grabs! ??\n\n? Date: 14